import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { 
  LogOut, RefreshCcw, MapPin, Clock, Phone, 
  Smartphone, Car, Navigation, CheckCircle, 
  XCircle, Send, Calendar, Activity, Loader2, Info
} from "lucide-react";

const Dashboard = ({ session }) => {
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("all");

  useEffect(() => {
    fetchRides();
    const subscription = supabase
      .channel('rides-admin-v2')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides())
      .subscribe();

    return () => supabase.removeChannel(subscription);
  }, []);

  const fetchRides = async () => {
    const { data, error } = await supabase
      .from("rides")
      .select("*")
      .order("created_at", { ascending: false });

    if (!error) setRides(data);
    setLoading(false);
  };

  const updateStatus = async (id, newStatus) => {
    await supabase.from('rides').update({ status: newStatus }).eq('id', id);
    fetchRides();
  };

  // Stats Logic
  const todayDate = new Date().toISOString().split('T')[0];
  const stats = {
    total: rides.length,
    pending: rides.filter(r => r.status === 'pending').length,
    today: rides.filter(r => r.ride_date === todayDate).length,
    completed: rides.filter(r => r.status === 'completed').length
  };

  const filteredData = filter === "all" ? rides : rides.filter(r => r.status === filter);

  // Formatting Date/Time for Display
  const formatDateTime = (timestamp) => {
    const d = new Date(timestamp);
    return d.toLocaleString('en-IN', { dateStyle: 'medium', timeStyle: 'short' });
  };

  if (loading) return (
    <div style={{ display: "flex", height: "100vh", alignItems: "center", justifyContent: "center", background: "#fdf2f5" }}>
      <Loader2 className="spin" size={40} color="#e55a7b" />
    </div>
  );

  return (
    <div className="admin-body">
      {/* Dynamic CSS for Responsiveness */}
      <style>{`
        .admin-body { min-height: 100vh; background: #fdf2f5; padding: 20px; font-family: 'Inter', sans-serif; }
        .stats-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 15px; margin-bottom: 25px; }
        .stat-card { background: #fff; padding: 20px; border-radius: 20px; border-left: 5px solid #e55a7b; box-shadow: 0 4px 15px rgba(0,0,0,0.03); }
        .responsive-table { width: 100%; border-collapse: collapse; background: white; border-radius: 20px; overflow: hidden; box-shadow: 0 10px 30px rgba(0,0,0,0.03); }
        .responsive-table th { background: #fdf2f5; padding: 15px; text-align: left; font-size: 14px; color: #636e72; }
        .responsive-table td { padding: 15px; border-bottom: 1px solid #f9f9f9; vertical-align: top; }

        @media (max-width: 768px) {
          .responsive-table thead { display: none; }
          .responsive-table tr { display: block; margin-bottom: 15px; border: 1px solid #eee; border-radius: 15px; padding: 10px; background: #fff; }
          .responsive-table td { display: block; text-align: right; padding-left: 50%; position: relative; border-bottom: none; }
          .responsive-table td::before { content: attr(data-label); position: absolute; left: 15px; font-weight: 700; color: #e55a7b; text-transform: uppercase; font-size: 11px; }
          .stats-grid { grid-template-columns: 1fr 1fr; }
          .nav-header { flex-direction: column; gap: 15px; text-align: center; }
          .filter-bar { overflow-x: auto; white-space: nowrap; width: 100%; padding-bottom: 10px; }
        }

        .spin { animation: rotate 1s linear infinite; }
        @keyframes rotate { 100% { transform: rotate(360deg); } }
        .btn-action { padding: 8px; border-radius: 10px; border: 1px solid #eee; cursor: pointer; transition: 0.2s; background: #fff; }
        .btn-action:hover { transform: translateY(-2px); box-shadow: 0 4px 10px rgba(0,0,0,0.1); }
      `}</style>

      {/* Header */}
      <div className="nav-header" style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "30px" }}>
        <div>
          <h1 style={{ margin: 0, color: "#2d3436", fontSize: "24px", display: "flex", alignItems: "center", gap: "10px" }}>
            <Navigation color="#e55a7b" /> PAHEL Portal
          </h1>
          <p style={{ color: "#636e72", fontSize: "14px", margin: "5px 0" }}>Logged in: {session.user.email}</p>
        </div>
        <button onClick={() => supabase.auth.signOut()} style={{ background: "#fff", border: "1px solid #e55a7b", color: "#e55a7b", padding: "8px 20px", borderRadius: "12px", cursor: "pointer", fontWeight: "600", display: "flex", alignItems: "center", gap: "8px" }}>
          <LogOut size={16} /> Logout
        </button>
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card">
          <p style={{ fontSize: "12px", color: "#636e72", margin: 0 }}>Total Bookings</p>
          <h2 style={{ margin: "5px 0", color: "#2d3436" }}>{stats.total}</h2>
        </div>
        <div className="stat-card" style={{ borderLeftColor: "#f59e0b" }}>
          <p style={{ fontSize: "12px", color: "#636e72", margin: 0 }}>Pending</p>
          <h2 style={{ margin: "5px 0", color: "#2d3436" }}>{stats.pending}</h2>
        </div>
        <div className="stat-card" style={{ borderLeftColor: "#3b82f6" }}>
          <p style={{ fontSize: "12px", color: "#636e72", margin: 0 }}>Today's Rides</p>
          <h2 style={{ margin: "5px 0", color: "#2d3436" }}>{stats.today}</h2>
        </div>
        <div className="stat-card" style={{ borderLeftColor: "#10b981" }}>
          <p style={{ fontSize: "12px", color: "#636e72", margin: 0 }}>Completed</p>
          <h2 style={{ margin: "5px 0", color: "#2d3436" }}>{stats.completed}</h2>
        </div>
      </div>

      {/* Filters & Refresh */}
      <div style={{ background: "#fff", borderRadius: "24px", padding: "20px", marginBottom: "20px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: "15px" }}>
          <div className="filter-bar" style={{ display: "flex", gap: "10px" }}>
            {['all', 'pending', 'confirmed', 'completed'].map(m => (
              <button key={m} onClick={() => setFilter(m)} style={{ padding: "8px 18px", borderRadius: "10px", border: "none", background: filter === m ? "#e55a7b" : "#fdf2f5", color: filter === m ? "#fff" : "#e55a7b", cursor: "pointer", fontWeight: "600", fontSize: "13px", textTransform: "capitalize" }}>{m}</button>
            ))}
          </div>
          <button onClick={fetchRides} style={{ background: "#fff", border: "1px solid #eee", padding: "10px", borderRadius: "12px", cursor: "pointer" }}>
            <RefreshCcw size={18} color="#e55a7b" />
          </button>
        </div>
      </div>

      {/* Main Responsive Table */}
      <div style={{ overflowX: "auto" }}>
        <table className="responsive-table">
          <thead>
            <tr>
              <th>Passenger Info</th>
              <th>Route Details</th>
              <th>Booked Date/Time</th>
              <th>Ride Schedule</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredData.map(ride => (
              <tr key={ride.id}>
                <td data-label="Passenger">
                  <div style={{ fontWeight: "700" }}>{ride.passenger_name}</div>
                  <div style={{ fontSize: "12px" }}><Phone size={10}/> {ride.phone_number}</div>
                  {ride.alt_phone && <div style={{ fontSize: "12px", color: "#999" }}><Smartphone size={10}/> {ride.alt_phone}</div>}
                </td>
                <td data-label="Route">
                  <div style={{ fontSize: "12px", color: "#27ae60" }}><MapPin size={10}/> {ride.pickup_location}</div>
                  <div style={{ fontSize: "12px", color: "#e74c3c" }}><Navigation size={10}/> {ride.drop_location}</div>
                </td>
                <td data-label="Booking Time">
                  <div style={{ fontSize: "11px", color: "#636e72" }}>
                    <Info size={10} /> {formatDateTime(ride.created_at)}
                  </div>
                </td>
                <td data-label="Scheduled For">
                  <div style={{ fontSize: "13px", fontWeight: "600" }}>
                    <Calendar size={12}/> {ride.ride_date}
                  </div>
                  <div style={{ fontSize: "13px" }}>
                    <Clock size={12}/> {ride.ride_time}
                  </div>
                </td>
                <td data-label="Status">
                  <span style={{ 
                    padding: "4px 10px", borderRadius: "8px", fontSize: "11px", fontWeight: "800",
                    background: ride.status === 'pending' ? '#fff3cd' : '#d4edda',
                    color: ride.status === 'pending' ? '#856404' : '#155724',
                    textTransform: "uppercase"
                  }}>
                    {ride.status}
                  </span>
                </td>
                <td data-label="Actions">
                  <div style={{ display: "flex", gap: "8px", justifyContent: "flex-end" }}>
                    <button title="Confirm" onClick={() => updateStatus(ride.id, 'confirmed')} className="btn-action"><Send size={14} color="#3b82f6"/></button>
                    <button title="Complete" onClick={() => updateStatus(ride.id, 'completed')} className="btn-action"><CheckCircle size={14} color="#10b981"/></button>
                    <button title="Cancel" onClick={() => updateStatus(ride.id, 'cancelled')} className="btn-action"><XCircle size={14} color="#ef4444"/></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filteredData.length === 0 && (
          <div style={{ textAlign: "center", padding: "40px", background: "#fff", borderRadius: "0 0 20px 20px", color: "#636e72" }}>No records found.</div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
